  // ==================== Knowledge Base Routes (Protected) ====================

  // Get knowledge bases for an agent
  // Helper: ambil agen pemilik sebuah KB (lewat knowledgeBases.agentId).
  // Dipakai guard mutasi KB agar otorisasi mengikuti kepemilikan AGEN, bukan
  // sekadar "sudah login" (mencegah IDOR: user lain mengedit KB agen orang lain
  // atau ~900 agen sistem). Return null kalau KB / agen tidak ditemukan.
  async function getAgentForKB(kbId: string): Promise<any | null> {
    const numId = parseInt(kbId);
    if (Number.isNaN(numId)) return null;
    const [row] = await db.select().from(knowledgeBases).where(eq(knowledgeBases.id, numId));
    if (!row) return null;
    return storage.getAgent(String((row as any).agentId));
  }

  app.get("/api/knowledge-base/:agentId", isAuthenticated, async (req, res) => {
    try {
      const agent = await storage.getAgent(req.params.agentId as string);
      if (!agent) return res.status(404).json({ error: "Agent not found" });
      const auth = await assertCanAccessAgentChat(req, agent);
      if (!auth.ok) return res.status(auth.status).json({ error: auth.error });
      const kbs = await storage.getKnowledgeBases(req.params.agentId as string);
      res.json(kbs);
    } catch (error) {
      res.status(500).json({ error: "Failed to fetch knowledge bases" });
    }
  });

  // ── Research Feed sweep — beri "mata" nyata ke tim riset (Google News RSS → KB) ──
  // Owner/admin dari agen feed yang boleh memicu. Resolusi agen via slug (bukan ID).
  app.post("/api/research/sweep", isAuthenticated, requireAdmin, async (req, res) => {
    try {
      const { runResearchSweep, FEED_STREAMS, AD_MATERIAL_SLUG, RETENTION_SLUG, CLOSING_SLUG } =
        await import("./lib/research-feed");
      // Sweep MENULIS ke SEMUA agen stream feed + agen pipeline (materi iklan, retensi, closing).
      // Otorisasi wajib untuk SETIAP agen yang akan dimutasi (cegah cross-agent privilege bleed
      // bila kepemilikan berbeda). Topik feed = fixed defaults (tak ada input user → tak ada vektor abuse).
      const feedAgents = (await Promise.all(
        FEED_STREAMS.map((s) => storage.getAgentBySlug(s.slug)),
      )).filter(Boolean);
      if (feedAgents.length === 0) {
        return res.status(404).json({ error: "Agen feed riset belum dibuat (slug riset-viral-lokal / riset-tren-global / riset-iklan-pasar tidak ditemukan)." });
      }
      // Agen pipeline tambahan yang juga dimutasi sweep (skip bila belum dibuat — sweep juga skip).
      const pipelineAgents = (await Promise.all(
        [AD_MATERIAL_SLUG, RETENTION_SLUG, CLOSING_SLUG].map((slug) => storage.getAgentBySlug(slug)),
      )).filter(Boolean);
      for (const a of [...feedAgents, ...pipelineAgents]) {
        const auth = await assertCanMutateAgent(req, a);
        if (!auth.ok) return res.status(auth.status).json({ error: auth.error });
      }

      const result = await runResearchSweep();
      res.json({ ok: true, result });
    } catch (error) {
      console.error("[/api/research/sweep]", error);
      res.status(500).json({ error: "Gagal menjalankan research sweep", details: error instanceof Error ? error.message : String(error) });
    }
  });

