  // POST /api/store/order/manual — admin creates access link manually (no Midtrans)
  app.post("/api/store/order/manual", isAuthenticated, async (req: any, res) => {
    try {
      const userId = req.user?.claims?.sub;
      if (!userId) return res.status(401).json({ error: "Unauthorized" });
      const adminIds = (process.env.ADMIN_USER_IDS || "").split(",").map((id: string) => id.trim()).filter(Boolean);
      const superAdminEmails = (process.env.SUPERADMIN_EMAILS || "").split(",").map((e: string) => e.trim()).filter(Boolean);
      const { db: dbCheck } = await import("./db");
      const { users: usersTable } = await import("@shared/schema");
      const { eq: eqCheck } = await import("drizzle-orm");
      const userRows = await dbCheck.select({ role: usersTable.role, email: usersTable.email }).from(usersTable).where(eqCheck(usersTable.id, userId)).limit(1);
      const dbRole = userRows[0]?.role;
      const dbEmail = userRows[0]?.email;
      const isAdminCheck = adminIds.includes(userId) || superAdminEmails.includes(dbEmail || "") || dbRole === "admin" || dbRole === "superadmin";
      if (!isAdminCheck) {
        const _ipOrd = (req.headers["x-forwarded-for"] as string | undefined)?.split(",")[0]?.trim() || req.socket?.remoteAddress || "unknown";
        console.warn(`[ADMIN_DENIED] 403 store-order-manual | userId=${userId} | ip=${_ipOrd} | path=${req.path}`);
        return res.status(403).json({ error: "Admin only" });
      }

      const { agentId, name, email, phone } = req.body;
      if (!name || !email || !agentId) {
        return res.status(400).json({ error: "name, email, dan agentId wajib diisi" });
      }

      const { db } = await import("./db");
      const { agents: agentsTable } = await import("@shared/schema");
      const { eq } = await import("drizzle-orm");
      const { randomUUID } = await import("crypto");

      const rows = await db.select({ id: agentsTable.id, name: agentsTable.name, userId: agentsTable.userId, licensePrice: agentsTable.licensePrice, licenseClass: agentsTable.licenseClass })
        .from(agentsTable).where(eq(agentsTable.id, Number(agentId))).limit(1);
      const agent = rows[0];
      if (!agent) return res.status(404).json({ error: "Agen tidak ditemukan" });

      const orderId = `MANUAL-${Date.now()}-${randomUUID().split("-")[0].toUpperCase()}`;
      const accessToken = randomUUID();

      // Harga lisensi efektif (band kelas / harga bebas / DEFAULT) — TERPISAH dari monthlyPrice.
      const manualAmount = resolveLicensePrice(agent.licenseClass, agent.licensePrice);
      // Bagi hasil 80/20 dari lisensi bila produk buatan kreator; jika tidak 100% platform.
      const manualCreatorUserId = (agent.userId ?? "").trim() || null;
      const manualCreatorShare = manualCreatorUserId ? Math.round(manualAmount * 0.8) : 0;
      const manualPlatformShare = manualAmount - manualCreatorShare;

      const order = await storage.createStoreOrder({
        productId: 0,
        agentId: agent.id,
        customerName: name,
        customerEmail: email,
        customerPhone: phone || "",
        amount: manualAmount,
        creatorUserId: manualCreatorUserId,
        creatorShare: manualCreatorShare,
        platformShare: manualPlatformShare,
        midtransOrderId: orderId,
        accessToken,
        status: "paid",
      });

      const accessUrl = `${getServerBaseUrl(req)}/store/access/${accessToken}`;
      res.json({ success: true, accessToken, accessUrl, orderId, agentName: agent.name });
    } catch (error) {
      console.error("Manual order error:", error);
      res.status(500).json({ error: "Gagal membuat order manual" });
    }
  });

