  app.post("/api/wa-broadcasts/:id/send-now", isAuthenticated, async (req, res) => {
    try {
      const broadcast = await storage.getWaBroadcast(req.params.id as string);
      if (!broadcast) return res.status(404).json({ error: "Broadcast not found" });

      const contacts = await storage.getWaContacts(String(broadcast.agentId));
      const activeContacts = contacts.filter(c => !c.isOptedOut);
      if (activeContacts.length === 0) return res.status(400).json({ error: "No active contacts" });

      const agentIntegrations = await storage.getIntegrations(String(broadcast.agentId));
      const waIntegration = agentIntegrations.find(i => i.type === "whatsapp" && i.isEnabled);
      const waConfig = (waIntegration?.config || {}) as Record<string, string>;
      const waApiToken = waConfig.apiToken || waConfig.token;
      if (!waApiToken) return res.status(400).json({ error: "WhatsApp integration not configured" });

      const run = await storage.createBroadcastRun({
        broadcastId: broadcast.id,
        status: "running",
        totalRecipients: activeContacts.length,
      });

      let message = broadcast.messageTemplate;
      if (broadcast.dataSource === "tender_daily") {
        const latestTenders = await storage.getLatestTenders(10);
        if (latestTenders.length > 0) {
          const tenderList = latestTenders.map((t, i) => 
            `${i + 1}. ${t.name}\n   ${t.agency} | ${t.budget}\n   ${t.url}`
          ).join("\n\n");
          message = message.replace("{{tender_list}}", tenderList);
          message = message.replace("{{date}}", new Date().toLocaleDateString("id-ID"));
          message = message.replace("{{count}}", String(latestTenders.length));
        }
      }

      let sent = 0, failed = 0;
      const errors: string[] = [];
      for (const contact of activeContacts) {
        try {
          await fetch("https://api.fonnte.com/send", {
            method: "POST",
            headers: { "Authorization": waApiToken },
            body: new URLSearchParams({
              target: contact.phone,
              message: message.replace("{{name}}", contact.name || ""),
            }),
          });
          sent++;
          if (activeContacts.length > 5) await new Promise(r => setTimeout(r, 1000));
        } catch (err: any) {
          failed++;
          errors.push(`${contact.phone}: ${err.message}`);
        }
      }

      await storage.updateBroadcastRun(String(run.id), {
        status: "completed",
        totalSent: sent,
        totalFailed: failed,
        completedAt: new Date(),
        errorLog: errors.join("\n"),
      });

      await storage.updateWaBroadcast(String(broadcast.id), { lastRunAt: new Date() } as any);

      res.json({ success: true, sent, failed, total: activeContacts.length });
    } catch (error) {
      res.status(500).json({ error: "Failed to send broadcast" });
    }
  });

  // ==================== Tender Ingest (Relay Eksternal SIRUP) ====================
  // Menerima data tender dari skrip relay yang berjalan di server/komputer Indonesia
  // (sirup.lkpp.go.id tidak dapat diakses dari lingkungan hosting ini).
  // Auth: header x-tender-ingest-key harus cocok dengan env TENDER_INGEST_KEY.
  const tenderIngestItemSchema = z.object({
    tenderId: z.string().min(1).max(200),
    name: z.string().min(1).max(2000),
    agency: z.string().max(1000).optional().default(""),
    budget: z.string().max(200).optional().default(""),
    type: z.string().max(500).optional().default(""),
    sector: z.string().max(100).optional().default("konstruksi"),
    status: z.string().max(200).optional().default(""),
    stage: z.string().max(500).optional().default(""),
    location: z.string().max(1000).optional().default(""),
    publishDate: z.string().max(100).optional().default(""),
    deadlineDate: z.string().max(100).optional().default(""),
    url: z.string().max(2000).optional().default(""),
  });
  const tenderIngestBodySchema = z.object({
    tenders: z.array(tenderIngestItemSchema).min(1).max(500),
  });

  // Rate limiter sederhana per-IP untuk jalur ingest publik (30 request/menit)
  const ingestHits = new Map<string, number[]>();
  const ingestRateLimit = (req: any, res: any, next: any) => {
    const ip = String(req.ip || req.socket?.remoteAddress || "unknown");
    const now = Date.now();
    const hits = (ingestHits.get(ip) || []).filter((t) => now - t < 60_000);
    if (hits.length >= 30) {
      return res.status(429).json({ error: "Terlalu banyak request, coba lagi sebentar" });
    }
    hits.push(now);
    ingestHits.set(ip, hits);
    if (ingestHits.size > 1000) {
      for (const [k, v] of ingestHits) {
        if (v.every((t) => now - t >= 60_000)) ingestHits.delete(k);
      }
    }
    next();
  };

  app.post("/api/tender-ingest", ingestRateLimit, async (req, res) => {
    try {
      const ingestKey = process.env.TENDER_INGEST_KEY;
      if (!ingestKey) {
        return res.status(503).json({ error: "TENDER_INGEST_KEY belum dikonfigurasi di server" });
      }
      const provided = String(req.header("x-tender-ingest-key") || "");
      const cryptoMod = await import("node:crypto");
      const a = Buffer.from(provided);
      const b = Buffer.from(ingestKey);
      const keyOk = a.length === b.length && cryptoMod.timingSafeEqual(a, b);
      if (!keyOk) {
        return res.status(401).json({ error: "Kunci ingest tidak valid" });
      }

      const parsed = tenderIngestBodySchema.safeParse(req.body);
      if (!parsed.success) {
        return res.status(400).json({ error: "Payload tidak valid", details: parsed.error.issues.slice(0, 5) });
      }

      // Cari/buat sumber "SIRUP (Relay)" — semua data relay masuk ke satu sumber ini
      const sources = await storage.getTenderSources();
      let relaySource = sources.find((s) => s.sourceType === "sirup");
      if (!relaySource) {
        relaySource = await storage.createTenderSource({
          userId: "",
          name: "SIRUP LKPP (Relay Eksternal)",
          baseUrl: "https://sirup.lkpp.go.id",
          sourceType: "sirup",
          sector: "multiple",
          region: "Nasional",
        } as any);
      }

      let saved = 0;
      try {
      for (const item of parsed.data.tenders) {
        await storage.upsertTender({
          sourceId: relaySource.id,
          tenderId: item.tenderId,
          name: item.name,
          agency: item.agency,
          budget: item.budget,
          type: item.type,
          sector: item.sector,
          sourceType: "sirup",
          status: item.status,
          stage: item.stage,
          location: item.location,
          publishDate: item.publishDate,
          deadlineDate: item.deadlineDate,
          url: item.url,
          rawData: {},
        } as any);
        saved++;
      }
      } catch (loopErr) {
        // Catat status error di sumber agar terlihat di UI monitor
        await storage.updateTenderSource(String(relaySource.id), {
          scrapeStatus: "error",
          lastError: `Ingest gagal setelah ${saved} tender: ${(loopErr as Error).message}`,
        } as any).catch(() => {});
        throw loopErr;
      }

      await storage.updateTenderSource(String(relaySource.id), {
        scrapeStatus: "success",
        lastError: "",
        lastScrapedAt: new Date(),
      } as any);

      console.log(`[Tender Ingest] Relay eksternal menyimpan ${saved} tender (source ${relaySource.id})`);
      res.json({ success: true, saved, sourceId: relaySource.id });
    } catch (err) {
      console.error("[/api/tender-ingest]", err);
      res.status(500).json({ error: "Gagal menyimpan data tender" });
    }
  });

