  // PARTNER-ADMIN: ajukan permintaan top-up kursi/kuota. Menotifikasi admin Gustafta (fire-and-forget).
  app.post("/api/partner/me/topup-requests", optionalAuthWithEmail, async (req: any, res) => {
    try {
      const resolved = await resolvePartnerForAdmin(req);
      if (!resolved) return res.status(403).json({ error: "Anda bukan pengurus mitra terdaftar." });
      const { partner, email } = resolved;
      const kind = req.body.kind === "quota" ? "quota" : req.body.kind === "seats" ? "seats" : null;
      const amount = Math.floor(Number(req.body.amount));
      const note = req.body.note ? String(req.body.note).slice(0, 500).trim() : null;
      if (!kind) return res.status(400).json({ error: "Jenis top-up tidak valid (seats/quota)." });
      if (!Number.isFinite(amount) || amount <= 0) return res.status(400).json({ error: "Jumlah harus lebih dari 0." });
      const [inserted] = await db.insert(partnerTopupRequests).values({
        partnerId: partner.id,
        requestedByEmail: email,
        kind,
        amount,
        note,
      }).returning();

      // Notifikasi admin Gustafta — fire-and-forget, tidak boleh menggagalkan permintaan.
      (async () => {
        try {
          const { sendPartnerTopupRequestNotification } = await import("./lib/email");
          const adminTo = (process.env.ADMIN_EMAILS || "").split(",").map((s) => s.trim()).filter(Boolean)[0]
            || process.env.BREVO_SENDER_EMAIL
            || "support@gustafta.com";
          await sendPartnerTopupRequestNotification({
            to: adminTo,
            partnerName: partner.name,
            requestedByEmail: email,
            kind,
            amount,
            currentValue: kind === "seats" ? partner.seatsPerUnit : partner.monthlyQuota,
            note,
          });
        } catch (e) {
          console.error("[partner-topup] notify failed:", (e as any)?.message || e);
        }
      })();

      res.status(201).json(inserted);
    } catch (error) {
      res.status(500).json({ error: "Gagal mengirim permintaan top-up" });
    }
  });

  // ==================== Admin: Partner Top-Up Requests ====================
  // ADMIN: daftar permintaan top-up (default hanya pending). Beri ?status=all untuk semua.
  app.get("/api/admin/partners/topup-requests", isAuthenticated, async (req: any, res) => {
    try {
      if (!(await isRequestAdmin(req))) return res.status(403).json({ error: "Akses ditolak" });
      const statusFilter = String(req.query.status || "pending");
      const base = db.select().from(partnerTopupRequests);
      const rows = statusFilter === "all"
        ? await base.orderBy(desc(partnerTopupRequests.createdAt))
        : await db.select().from(partnerTopupRequests)
            .where(eq(partnerTopupRequests.status, statusFilter))
            .orderBy(desc(partnerTopupRequests.createdAt));
      res.json(rows);
    } catch (error) {
      res.status(500).json({ error: "Gagal memuat permintaan top-up" });
    }
  });

  // ADMIN: setujui/tolak permintaan top-up.
  // Approve → tambahkan increase ke partner (seats→seatsPerUnit, quota→monthlyQuota) + set status resolved.
  // Reject → set status rejected. Keduanya atomik dan hanya berlaku untuk request yang masih pending.
  app.patch("/api/admin/partners/topup-requests/:id", isAuthenticated, async (req: any, res) => {
    try {
      if (!(await isRequestAdmin(req))) return res.status(403).json({ error: "Akses ditolak" });
      const action = req.body.action === "approve" ? "approve" : req.body.action === "reject" ? "reject" : null;
      if (!action) return res.status(400).json({ error: "Aksi tidak valid (approve/reject)." });
      const reqId = Number(req.params.id);
      if (!Number.isFinite(reqId)) return res.status(400).json({ error: "ID tidak valid." });

      const result = await db.transaction(async (tx) => {
        const [request] = await tx.select().from(partnerTopupRequests)
          .where(eq(partnerTopupRequests.id, reqId))
          .for("update");
        if (!request) return { error: "notfound" as const };
        if (request.status !== "pending") return { error: "resolved" as const };

        if (action === "approve") {
          const [partner] = await tx.select().from(partners)
            .where(eq(partners.id, request.partnerId))
            .for("update");
          if (!partner) return { error: "partner_notfound" as const };
          if (request.kind === "seats") {
            await tx.update(partners)
              .set({ seatsPerUnit: partner.seatsPerUnit + request.amount, updatedAt: new Date() })
              .where(eq(partners.id, partner.id));
          } else {
            await tx.update(partners)
              .set({ monthlyQuota: partner.monthlyQuota + request.amount, updatedAt: new Date() })
              .where(eq(partners.id, partner.id));
          }
          const [updated] = await tx.update(partnerTopupRequests)
            .set({ status: "resolved", resolvedAt: new Date() })
            .where(eq(partnerTopupRequests.id, reqId))
            .returning();
          return { request: updated };
        }

        const [updated] = await tx.update(partnerTopupRequests)
          .set({ status: "rejected", resolvedAt: new Date() })
          .where(eq(partnerTopupRequests.id, reqId))
          .returning();
        return { request: updated };
      });

      if (result.error === "notfound") return res.status(404).json({ error: "Permintaan tidak ditemukan." });
      if (result.error === "resolved") return res.status(409).json({ error: "Permintaan sudah diproses." });
      if (result.error === "partner_notfound") return res.status(404).json({ error: "Mitra tidak ditemukan." });
      res.json(result.request);
    } catch (error) {
      res.status(500).json({ error: "Gagal memproses permintaan top-up" });
    }
  });

  // ─── AI Big Idea Generator ────────────────────────────────────
  const extractFileUpload = multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 5 * 1024 * 1024 },
    fileFilter: (_req, file, cb) => {
      const ext = file.originalname.toLowerCase();
      const validExt = ext.endsWith(".pdf") || ext.endsWith(".txt") || ext.endsWith(".docx");
      const validMime = [
        "application/pdf",
        "text/plain",
        "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
      ].includes(file.mimetype);
      if (validExt || validMime) {
        cb(null, true);
      } else {
        cb(new Error("Format tidak didukung. Gunakan PDF, DOCX, atau TXT."));
      }
    },
  });

  app.post("/api/ai/extract-file-text", isAuthenticated, (req, res, next) => {
    extractFileUpload.single("file")(req, res, (err) => {
      if (err) {
        const msg = err.message || "Upload gagal";
        if (err.code === "LIMIT_FILE_SIZE") {
          return res.status(413).json({ error: "File terlalu besar. Maksimal 5 MB." });
        }
        return res.status(400).json({ error: msg });
      }
      next();
    });
  }, async (req, res) => {
    try {
      if (!req.file) {
        return res.status(400).json({ error: "File tidak ditemukan" });
      }
      const { originalname, mimetype, buffer } = req.file;
      let text = "";

      if (mimetype === "text/plain" || originalname.toLowerCase().endsWith(".txt")) {
        text = buffer.toString("utf-8");
      } else if (
        mimetype === "application/vnd.openxmlformats-officedocument.wordprocessingml.document" ||
        originalname.toLowerCase().endsWith(".docx")
      ) {
        const mammoth = (await import("mammoth")).default;
        const result = await mammoth.extractRawText({ buffer });
        text = result.value;
      } else {
        
        // PDF parsing (pdf-parse v2 API)
        text = await parsePdfBuffer(buffer);
      }

      text = text.replace(/\r\n/g, "\n").replace(/\n{3,}/g, "\n\n").trim();

      if (!text || text.length < 20) {
        return res.status(422).json({ error: "Teks tidak dapat diekstrak. Pastikan file tidak terenkripsi atau kosong." });
      }

      res.json({ text, filename: originalname, charCount: text.length });
    } catch (error: any) {
      console.error("Extract file text error:", error);
      res.status(500).json({ error: "Gagal mengekstrak teks: " + (error.message || "Unknown error") });
    }
  });

  app.post("/api/ai/generate-big-ideas", isAuthenticated, async (req, res) => {
    try {
      const { referenceText, urls, topic, count = 6 } = req.body;
      if (!referenceText && (!urls || urls.length === 0) && !topic) {
        return res.status(400).json({ error: "Butuh minimal satu referensi: teks, URL, atau topik" });
      }

      const refBlock = referenceText ? `\n\n=== KONTEN REFERENSI ===\n${referenceText.slice(0, 8000)}` : "";
      const urlBlock = urls && urls.length > 0 ? `\n\n=== URL REFERENSI ===\n${urls.join("\n")}` : "";
      const topicBlock = topic ? `\n\nTOPIK/BIDANG: ${topic}` : "";

      const systemPrompt = `Kamu adalah AI konsultan ekosistem chatbot untuk platform Gustafta (Indonesia). Tugasmu adalah menganalisis referensi yang diberikan dan menghasilkan saran Big Idea/Modul chatbot yang paling menarik dan bernilai tinggi untuk dibangun.

Setiap Big Idea harus:
- Spesifik dan actionable (bukan generik)
- Bernilai tinggi bagi pengguna target
- Dapat diimplementasikan sebagai chatbot interaktif berbasis AI
- Relevan dengan konteks Indonesia (konstruksi, bisnis, pendidikan, hukum, dll)

Selalu return JSON valid dengan format yang diminta.`;

      const userPrompt = `Analisis referensi berikut dan hasilkan TEPAT ${count} saran Big Idea/Modul chatbot yang paling menarik:${topicBlock}${refBlock}${urlBlock}

Return HANYA JSON berikut (tanpa penjelasan lain):
{
  "suggestions": [
    {
      "name": "Nama Big Idea (max 60 karakter)",
      "type": "idea|inspiration|problem|mentoring",
      "description": "Deskripsi 2-3 kalimat tentang apa yang dilakukan chatbot ini",
      "goals": ["Goal 1", "Goal 2", "Goal 3"],
      "targetAudience": "Target pengguna spesifik",
      "reasoning": "Kenapa Big Idea ini menarik dan bernilai tinggi (1-2 kalimat)",
      "expectedOutcome": "Apa yang didapat pengguna setelah berinteraksi"
    }
  ]
}`;

      const deepseekKey = process.env.DEEPSEEK_API_KEY;
      const integrationKey = process.env.AI_INTEGRATIONS_OPENAI_API_KEY;
      const integrationBaseURL = process.env.AI_INTEGRATIONS_OPENAI_BASE_URL;

      let aiClient: OpenAI;
      let aiModel: string;

      if (deepseekKey) {
        aiClient = new OpenAI({ apiKey: deepseekKey, baseURL: "https://api.deepseek.com/v1" });
        aiModel = "deepseek-chat";
      } else if (integrationKey && integrationBaseURL) {
        aiClient = new OpenAI({ apiKey: integrationKey, baseURL: integrationBaseURL });
        aiModel = SMART_MODEL;
      } else {
        return res.status(503).json({ error: "Tidak ada AI provider yang tersedia. Silakan hubungi admin." });
      }

      const response = await aiClient.chat.completions.create({
        model: aiModel,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt },
        ],
        temperature: 0.8,
        max_tokens: 3000,
        response_format: { type: "json_object" },
      });

      const raw = response.choices[0]?.message?.content || "{}";
      let parsed: any = {};
      try { parsed = JSON.parse(raw); } catch { parsed = { suggestions: [] }; }
      if (!parsed.suggestions) parsed.suggestions = [];

      res.json({ suggestions: parsed.suggestions });
    } catch (error: any) {
      console.error("Generate big ideas error:", error);
      res.status(500).json({ error: "Gagal generate saran Big Idea: " + (error.message || "Unknown error") });
    }
  });

  // ==================== ADMIN HELPER ====================
  function getSessionUserId(req: any): string {
    return req.user?.claims?.sub || req.user?.id || "";
  }

  async function getDbRole(req: any): Promise<string> {
    const userId = getSessionUserId(req);
    if (!userId) return "user";
    const superadminEmails = (process.env.SUPERADMIN_EMAILS || "")
      .split(",").map((s: string) => s.trim().toLowerCase()).filter(Boolean);
    const adminEmails = (process.env.ADMIN_EMAILS || "")
      .split(",").map((s: string) => s.trim().toLowerCase()).filter(Boolean);
    const adminIds = (process.env.ADMIN_USER_IDS || "")
      .split(",").map((s: string) => s.trim()).filter(Boolean);
    const [dbUser] = await db.select({ role: users.role, email: users.email }).from(users).where(eq(users.id, userId));
    if (!dbUser) return adminIds.includes(userId) ? "superadmin" : "user";
    const userEmail = (dbUser.email || "").toLowerCase();
    if (superadminEmails.includes(userEmail)) return "superadmin";
    if (adminEmails.includes(userEmail)) return "admin";
    if (adminIds.includes(userId)) return dbUser.role === "superadmin" ? "superadmin" : "admin";
    return dbUser.role || "user";
  }

  async function checkIsAdmin(req: any): Promise<boolean> {
    const role = await getDbRole(req);
    return role === "admin" || role === "superadmin";
  }

  async function checkIsSuperAdmin(req: any): Promise<boolean> {
    const role = await getDbRole(req);
    return role === "superadmin";
  }

  function getClientIp(req: any): string {
    return (req.headers["x-forwarded-for"] as string | undefined)?.split(",")[0]?.trim()
      || req.socket?.remoteAddress
      || "unknown";
  }

  async function requireAdmin(req: any, res: any, next: any) {
    if (!req.user) {
      const ip = getClientIp(req);
      console.warn(`[ADMIN_DENIED] unauthenticated | ip=${ip} | path=${req.path}`);
      return res.status(401).json({ error: "Tidak terautentikasi" });
    }
    const ok = await checkIsAdmin(req);
    if (!ok) {
      const userId = (req.user as any)?.claims?.sub || (req.user as any)?.id || "unknown";
      const ip = getClientIp(req);
      console.warn(`[ADMIN_DENIED] 403 | userId=${userId} | ip=${ip} | path=${req.path}`);
      return res.status(403).json({ error: "Akses ditolak. Hanya admin yang dapat mengakses ini." });
    }
    next();
  }

  async function requireSuperAdmin(req: any, res: any, next: any) {
    if (!req.user) {
      const ip = getClientIp(req);
      console.warn(`[ADMIN_DENIED] unauthenticated | ip=${ip} | path=${req.path}`);
      return res.status(401).json({ error: "Tidak terautentikasi" });
    }
    const ok = await checkIsSuperAdmin(req);
    if (!ok) {
      const userId = (req.user as any)?.claims?.sub || (req.user as any)?.id || "unknown";
      const ip = getClientIp(req);
      console.warn(`[ADMIN_DENIED] 403 superadmin-required | userId=${userId} | ip=${ip} | path=${req.path}`);
      return res.status(403).json({ error: "Akses ditolak. Hanya Super Admin yang dapat melakukan ini." });
    }
    next();
  }

