  // Jadikan Early Adopter: aktifkan langganan tier penuh (gratis) untuk user tertentu,
  // tanpa user harus membuat permintaan paket / bayar. Admin pilih tier + durasi.
  app.post("/api/admin/users/:userId/early-adopter", isAuthenticated, requireAdmin, async (req: any, res: any) => {
    try {
      const { userId } = req.params;
      const { plan = "enterprise", durationDays = 365 } = req.body || {};

      const GUSTAFTA_PLAN_KEYS = ["starter", "profesional", "bisnis", "enterprise"];
      if (!GUSTAFTA_PLAN_KEYS.includes(plan)) {
        return res.status(400).json({ error: "Tier tidak valid. Gunakan starter, profesional, bisnis, atau enterprise." });
      }
      const duration = Number(durationDays);
      if (!Number.isFinite(duration) || duration < 1 || duration > 3650) {
        return res.status(400).json({ error: "Durasi tidak valid (1–3650 hari)." });
      }

      const [user] = await db.select().from(users).where(eq(users.id, userId));
      if (!user) return res.status(404).json({ error: "Pengguna tidak ditemukan." });

      const { PLAN_CONFIGS } = await import("@shared/feature-plans");
      const planConfig = (PLAN_CONFIGS as any)[plan];
      const chatbotLimit = Math.min(planConfig?.maxAgents ?? 3, 200);

      const now = new Date();
      const endDate = new Date(now.getTime() + duration * 24 * 60 * 60 * 1000);

      // Pastikan akun user aktif
      if (user.isActive === false) {
        await db.update(users).set({ isActive: true, updatedAt: new Date() }).where(eq(users.id, userId));
        invalidateUserActiveCache(userId);
      }

      // Atomik: nonaktifkan semua langganan aktif lama lalu catat 1 grant baru,
      // agar user tidak pernah punya lebih dari satu baris "active" sekaligus.
      await db.transaction(async (tx) => {
        await tx.update(subscriptionsTable)
          .set({ status: "expired", updatedAt: new Date() })
          .where(and(
            eq(subscriptionsTable.userId, userId),
            eq(subscriptionsTable.status, "active"),
          ));
        await tx.insert(subscriptionsTable).values({
          userId,
          plan,
          status: "active",
          amount: 0,
          currency: "IDR",
          chatbotLimit,
          grantedBy: req.user?.claims?.sub || null,
          mayarOrderId: `EARLY-${plan.toUpperCase()}-${userId.slice(0, 8)}-${Date.now()}`,
          startDate: now,
          endDate,
        });
      });

      res.json({
        success: true,
        message: `Early Adopter aktif: tier ${plan} gratis ${duration} hari (s/d ${endDate.toLocaleDateString("id-ID")}).`,
        plan,
        endDate: endDate.toISOString(),
      });
    } catch (error: any) {
      console.error("Admin early-adopter error:", error);
      res.status(500).json({ error: "Gagal mengaktifkan Early Adopter." });
    }
  });

  // ─── Access Codes: voucher akses peserta (mis. bonus seminar offline) ───────
  // Peserta menukar kode → langganan aktif otomatis (tanpa bayar).
  app.post("/api/access-codes/redeem", isAuthenticated, async (req: any, res: any) => {
    try {
      const userId = req.user?.claims?.sub;
      if (!userId) return res.status(401).json({ error: "Silakan masuk terlebih dahulu." });
      const code = String(req.body?.code || "").trim();
      if (!code) return res.status(400).json({ error: "Masukkan kode akses." });

      const result = await (storage as any).redeemAccessCode(code, userId);
      if (!result.ok) {
        const msg: Record<string, string> = {
          invalid: "Kode tidak ditemukan atau sudah tidak aktif.",
          already: "Anda sudah pernah menukarkan kode ini.",
          exhausted: "Kuota kode ini sudah habis.",
        };
        return res.status(400).json({ error: msg[result.reason] || "Kode tidak dapat digunakan." });
      }

      // Catatan: SENGAJA tidak menyentuh users.isActive di sini. Akun baru sudah
      // isActive=true secara default; isActive=false hanya dari tindakan admin
      // (suspend/pending), jadi menukar kode TIDAK boleh mengaktifkan ulang akun
      // yang sengaja dinonaktifkan. Akses tier dibuka oleh langganan, bukan flag ini.
      const endDate = result.endDate ? new Date(result.endDate) : null;
      res.json({
        success: true,
        message: `Akses ${result.plan} aktif${endDate ? ` s/d ${endDate.toLocaleDateString("id-ID")}` : ""}.`,
        plan: result.plan,
        endDate: result.endDate,
      });
    } catch (error: any) {
      console.error("Access code redeem error:", error);
      res.status(500).json({ error: "Gagal menukarkan kode. Coba lagi." });
    }
  });

