  // ── Scalev Webhook (PUBLIC — no auth) ──────────────────────────────────────
  // Scalev sends POST to this URL when order payment status changes.
  // Set this URL in app.scalev.id → Settings → Developers → Webhook URL
  app.post("/api/webhooks/scalev", async (req: any, res: any) => {
    try {
      // Verifikasi keaslian webhook (berlapis, aman-secara-default):
      //   1. Tanda tangan HMAC-SHA256 (SCALEV_SIGNING_SECRET) atas body mentah.
      //   2. Secret bersama (SCALEV_WEBHOOK_SECRET) via header / query `?secret=`.
      //   3. Tanpa secret sama sekali → terima (perilaku lama, non-breaking).
      // Mencegah pihak luar mengirim order palsu (mis. memicu clone Premium Privat
      // atau Purchase palsu ke Meta). Detail: server/lib/meta-capi.ts.
      const { verifyScalevWebhookAuth } = await import("./lib/meta-capi");
      const auth = verifyScalevWebhookAuth(req.rawBody, req.headers, req.query);
      if (!auth.authorized) {
        // Log NAMA header (bukan nilai) supaya format signature asli Scalev bisa
        // dikenali dari order pertama, tanpa membocorkan secret.
        const sigHeaderNames = Object.keys(req.headers || {})
          .filter((h) => /sign|secret|scalev|hmac|hub/i.test(h))
          .join(", ") || "(tidak ada header signature/secret)";
        console.warn(
          `[Scalev Webhook] Ditolak — tidak terautentikasi. signature: present=${auth.sigPresent} valid=${auth.sigValid} hdr=${auth.sigHeader || "none"}. Header masuk yang relevan: ${sigHeaderNames}`,
        );
        return res.status(401).json({ error: "Unauthorized" });
      }
      if (auth.method === "observe") {
        const relevantHeaders = Object.keys(req.headers || {})
          .filter((h) => /sign|secret|scalev|hmac|hub/i.test(h))
          .join(", ") || "(tidak ada header signature)";
        console.warn(
          `[Scalev Webhook] DITERIMA (mode observasi) — SCALEV_SIGNING_SECRET diset tapi signature belum cocok (present=${auth.sigPresent} hdr=${auth.sigHeader || "none"}). Header relevan: ${relevantHeaders}. Untuk gerbang WAJIB: set SCALEV_WEBHOOK_SECRET lalu tambahkan ?secret= di URL webhook; atau set SCALEV_SIGNATURE_STRICT=true setelah format signature dikonfirmasi.`,
        );
      } else if (process.env.SCALEV_SIGNING_SECRET) {
        console.log(
          `[Scalev Webhook] Auth OK via ${auth.method} (signature present=${auth.sigPresent} valid=${auth.sigValid} hdr=${auth.sigHeader || "none"})`,
        );
      }
      const payload = req.body;
      console.log("[Scalev Webhook]", JSON.stringify(payload).slice(0, 500));

      // Scalev sends different event types. We handle payment_status_changed + order.created/updated
      const data = payload.data || payload;
      const paymentStatus: string = data.payment_status || "";
      const orderId: string = data.order_id || "";
      const customer = data.customer || data.destination_address || {};
      const customerEmail: string = customer.email || "";
      const customerName: string = customer.name || data.payment_account_holder || "";
      const customerPhone: string = customer.phone || "";
      const grossRevenue: number = parseFloat(data.gross_revenue || data.net_revenue || "0");
      const finalVariants: Record<string, number> = data.final_variants || {};
      // Sinyal browser (fbp/fbc) yang mungkin diteruskan Scalev dari query checkout.
      // Best-effort: cek beberapa lokasi umum. Bila kosong, CAPI tetap jalan pakai email/telepon.
      const metaFbp: string | undefined =
        data.fbp || payload.fbp || customer.fbp || data.custom_fields?.fbp || data.metadata?.fbp || undefined;
      const metaFbc: string | undefined =
        data.fbc || payload.fbc || customer.fbc || data.custom_fields?.fbc || data.metadata?.fbc || undefined;
      const metaEventSourceUrl: string | undefined =
        data.esu || payload.esu || data.custom_fields?.esu || data.metadata?.esu || undefined;

      if (!orderId) {
        return res.status(200).json({ received: true, note: "No order_id" });
      }

      // Only process if payment is paid
      if (paymentStatus !== "paid") {
        return res.status(200).json({ received: true, note: `Payment status: ${paymentStatus}` });
      }

      // Check duplicate (use midtransOrderId field to store scalev orderId)
      const existing = await storage.getStoreOrderByMidtransId(`scalev_${orderId}`);
      if (existing) {
        return res.status(200).json({ received: true, note: "Duplicate, already processed" });
      }

      // ── Meta Conversions API: kirim event Purchase (fire-and-forget) ─────────
      // Jembatan Scalev → Meta: integrasi langsung Scalev↔Meta sering gagal, jadi
      // Gustafta yang meneruskan event Purchase server-side. Meta dedup via
      // event_id = scalev_{orderId}, jadi aman walau webhook diulang sebelum order
      // tercatat. JANGAN pernah blokir/ gagalkan webhook karena CAPI.
      (async () => {
        try {
          const { sendMetaPurchaseEvent } = await import("./lib/meta-capi");
          // Pakai pixel per-agen bila order terkait agen dengan metaPixelId
          let agentPixelId: string | undefined;
          let contentName: string | undefined;
          for (const pName of Object.keys(finalVariants)) {
            const m = await storage.getScalevMappingByProductName(pName).catch(() => null);
            if (m?.agentId) {
              const ag: any = await storage.getAgent(String(m.agentId)).catch(() => null);
              if (ag?.metaPixelId) agentPixelId = ag.metaPixelId;
              if (ag?.name) contentName = ag.name;
              break;
            }
          }
          const result = await sendMetaPurchaseEvent({
            orderId,
            value: grossRevenue,
            currency: "IDR",
            email: customerEmail || undefined,
            phone: customerPhone || undefined,
            name: customerName || undefined,
            contentName: contentName || Object.keys(finalVariants)[0] || undefined,
            pixelId: agentPixelId,
            fbp: metaFbp,
            fbc: metaFbc,
            externalId: customerEmail || undefined,
            eventSourceUrl: metaEventSourceUrl,
          });
          if (!result.sent && result.skippedReason) {
            console.log(`[Meta CAPI] Dilewati untuk order ${orderId}: ${result.skippedReason}`);
          }
        } catch (capiErr: any) {
          console.error("[Meta CAPI] Error tak terduga:", capiErr?.message);
        }
      })();
      // ─────────────────────────────────────────────────────────────────────────

      // ── Handle Gustafta Platform Subscription Plans ──────────────────────────
      // Detect if this is a platform subscription purchase (monthly_1/3/6/12)
      const GUSTAFTA_PLAN_SLUG_MAP: Record<string, { plan: string; duration: number }> = {
        "gustafta-paket-1-bulan":  { plan: "monthly_1",  duration: 30 },
        "gustafta-paket-3-bulan":  { plan: "monthly_3",  duration: 90 },
        "gustafta-paket-6-bulan":  { plan: "monthly_6",  duration: 180 },
        "gustafta-paket-12-bulan": { plan: "monthly_12", duration: 365 },
      };
      const productSlug: string = data.product_slug || data.slug || "";
      const slugFromName: string = (data.product_name || data.name || "")
        .toLowerCase().replace(/\s+/g, "-").replace(/[^a-z0-9-]/g, "");
      const matchedPlanConfig = GUSTAFTA_PLAN_SLUG_MAP[productSlug] || GUSTAFTA_PLAN_SLUG_MAP[slugFromName];

      if (matchedPlanConfig && customerEmail) {
        // Find user by email in users table
        const { db } = await import("./db");
        const { users } = await import("@shared/models/auth");
        const { eq } = await import("drizzle-orm");
        const userRows = await db.select().from(users).where(eq(users.email, customerEmail)).limit(1);
        if (userRows.length > 0) {
          const targetUserId = userRows[0].id;
          const now = new Date();
          const endDate = new Date(now.getTime() + matchedPlanConfig.duration * 24 * 60 * 60 * 1000);
          const { subscriptionPlans } = await import("./lib/mayar");
          const pricing = subscriptionPlans[matchedPlanConfig.plan as keyof typeof subscriptionPlans];
          try {
            const newSub = await storage.createSubscription({
              userId: targetUserId,
              plan: matchedPlanConfig.plan,
              status: "active",
              amount: Math.round(grossRevenue) || pricing?.price || 0,
              currency: "IDR",
              chatbotLimit: pricing?.chatbotLimit ?? 3,
              mayarOrderId: `scalev_plan_${orderId}`,
              startDate: now.toISOString(),
              endDate: endDate.toISOString(),
            });
            console.log(`[Scalev] Platform subscription activated for ${customerEmail}: ${matchedPlanConfig.plan} (${matchedPlanConfig.duration} days) sub#${newSub.id}`);
          } catch (subErr: any) {
            console.error(`[Scalev] Failed to activate platform subscription for ${customerEmail}:`, subErr?.message);
          }
        } else {
          console.log(`[Scalev] Platform sub webhook: no user found with email ${customerEmail}`);
        }
        return res.status(200).json({ received: true, type: "platform_subscription" });
      }
      // ─────────────────────────────────────────────────────────────────────────

      // Find matching product mappings by Scalev product variant names
      const productNames = Object.keys(finalVariants);
      let matchedMapping = null;
      for (const pName of productNames) {
        const m = await storage.getScalevMappingByProductName(pName);
        if (m) { matchedMapping = m; break; }
      }

      const { randomUUID: genUUID } = await import("crypto");
      const baseUrl = getServerBaseUrl(req);
      const accessToken = genUUID();

      if (matchedMapping) {
        if (matchedMapping.type === "chatbot" && matchedMapping.agentId) {
          // ── Premium Privat: tiap pembeli dapat SALINAN privat sendiri ──────────
          // Kalau agen master ber-premiumClass "private", jangan beri akses ke bot
          // bersama — clone untuk pembeli. Kalau pembeli belum punya akun, simpan
          // sebagai pending delivery yang otomatis di-clone saat mereka mendaftar.
          let masterAgent: any = null;
          try { masterAgent = await storage.getAgent(String(matchedMapping.agentId)); } catch {}
          if (masterAgent && (masterAgent as any).premiumClass === "private") {
            const buyer = customerEmail ? await storage.getUserByEmail(customerEmail) : undefined;
            if (buyer) {
              try {
                const existing = await storage.getCloneForOwner(matchedMapping.agentId, buyer.id);
                const clone = existing || await storage.cloneAgentForOwner(matchedMapping.agentId, buyer.id);
                console.log(`[Scalev] Premium Privat ${existing ? "sudah ada" : "clone"} #${clone.id} untuk ${customerEmail} (user ${buyer.id})`);
              } catch (cloneErr: any) {
                // Clone gagal (mis. error DB) — JANGAN hilangkan pembelian. Antrikan
                // pending agar di-clone otomatis saat pembeli login berikutnya.
                console.error(`[Scalev] Gagal clone Premium Privat untuk ${customerEmail}, di-antri pending:`, cloneErr?.message);
                try { await storage.addPendingPremiumDelivery({ masterAgentId: matchedMapping.agentId, email: customerEmail, source: "scalev" }); } catch {}
              }
            } else if (customerEmail) {
              await storage.addPendingPremiumDelivery({ masterAgentId: matchedMapping.agentId, email: customerEmail, source: "scalev" });
              console.log(`[Scalev] Premium Privat pending (belum daftar) untuk ${customerEmail} → master #${matchedMapping.agentId}`);
            }
            // Rekam order untuk audit; lewati grant akses bot bersama.
            await storage.createStoreOrder({
              productId: matchedMapping.agentId,
              customerName: customerName || "Customer",
              customerEmail: customerEmail,
              customerPhone: customerPhone,
              amount: Math.round(grossRevenue),
              midtransOrderId: `scalev_${orderId}`,
              accessToken,
              status: "paid",
            });
            return res.status(200).json({ received: true, type: "premium_private" });
          }
          // ──────────────────────────────────────────────────────────────────────
          // Create store order for chatbot access (for embed delivery)
          await storage.createStoreOrder({
            productId: matchedMapping.agentId,
            customerName: customerName || "Customer",
            customerEmail: customerEmail,
            customerPhone: customerPhone,
            amount: Math.round(grossRevenue),
            midtransOrderId: `scalev_${orderId}`,
            accessToken,
            status: "paid",
          });
          const accessUrl = `${baseUrl}/store/access/${accessToken}`;
          console.log(`[Scalev] Chatbot store order created for ${customerEmail}: ${accessUrl}`);

          // ALSO create a clientSubscription so requireRegistration chatbots grant chat access.
          // Agen yang melekat pada produk ebook (mis. AI Mentor Gustafta) diberi akses
          // seumur pembelian (bukan 30 hari) — itu bonus permanen dari buku, bukan langganan.
          const isEbookBoundAgent = masterAgent?.slug === "ai-mentor-gustafta";
          try {
            const subToken = genUUID();
            const subStart = new Date();
            const subEnd = new Date();
            subEnd.setDate(subEnd.getDate() + (isEbookBoundAgent ? 3650 : 30));
            await storage.createClientSubscription({
              agentId: String(matchedMapping.agentId),
              customerName: customerName || "Customer",
              customerEmail: customerEmail,
              customerPhone: customerPhone,
              plan: "scalev",
              status: "active",
              amount: Math.round(grossRevenue),
              accessToken: subToken,
              startDate: subStart,
              endDate: subEnd,
            } as any);
            console.log(`[Scalev] Chatbot clientSubscription created for ${customerEmail}`);

            if (isEbookBoundAgent && customerEmail && masterAgent) {
              const { sendAgentAccessDeliveryEmail } = await import("./lib/email");
              const agentRef = masterAgent.slug || masterAgent.id;
              sendAgentAccessDeliveryEmail({
                to: customerEmail,
                customerName,
                agentName: masterAgent.name || "AI Mentor Gustafta",
                chatUrl: `${baseUrl}/bot/${agentRef}`,
                bonusContext: "bonus dari pembelian Ebook Trilogi Gustafta",
              }).catch((emailErr: any) => console.error(`[Scalev] Gagal kirim email akses AI Mentor ke ${customerEmail}:`, emailErr?.message));
            }
          } catch (subErr: any) {
            console.error(`[Scalev] Failed to create clientSubscription for chatbot:`, subErr?.message);
          }
        } else if (matchedMapping.type === "modul" && matchedMapping.bigIdeaId) {
          // Create modul subscription
          const subToken = genUUID();
          await storage.createClientSubscription({
            bigIdeaId: matchedMapping.bigIdeaId,
            customerName: customerName || "Customer",
            customerEmail: customerEmail,
            customerPhone: customerPhone,
            plan: "scalev",
            status: "active",
            amount: Math.round(grossRevenue),
            accessToken: subToken,
            startDate: new Date(),
            endDate: (() => { const d = new Date(); d.setDate(d.getDate() + 30); return d; })(),
          } as any);
          const accessUrl = `${baseUrl}/modul/${matchedMapping.bigIdeaId}?email=${encodeURIComponent(customerEmail)}`;
          console.log(`[Scalev] Modul access created for ${customerEmail}: ${accessUrl}`);
        } else if (matchedMapping.type === "bundle" && (matchedMapping as any).agentIds?.length) {
          // Create clientSubscription for EACH agent in the bundle
          const bundleAgentIds: number[] = (matchedMapping as any).agentIds;
          const subEnd = new Date(); subEnd.setDate(subEnd.getDate() + 30);
          const created: number[] = [];
          for (const aid of bundleAgentIds) {
            try {
              const subToken = genUUID();
              await storage.createClientSubscription({
                agentId: String(aid),
                customerName: customerName || "Customer",
                customerEmail: customerEmail,
                customerPhone: customerPhone,
                plan: "scalev_bundle",
                status: "active",
                amount: Math.round(grossRevenue / bundleAgentIds.length),
                accessToken: subToken,
                startDate: new Date(),
                endDate: subEnd,
              } as any);
              created.push(aid);
            } catch (err: any) {
              console.error(`[Scalev Bundle] Failed for agent ${aid}:`, err?.message);
            }
          }
          console.log(`[Scalev Bundle] Created ${created.length}/${bundleAgentIds.length} subscriptions for ${customerEmail}: agents [${created.join(", ")}]`);
        } else if (matchedMapping.type === "ebook") {
          // ── Ebook Buku I — DIALOG (Rp79rb): kirim email fulfillment + trial 7 hari ──
          await storage.createStoreOrder({
            productId: 0,
            customerName: customerName || "Customer",
            customerEmail: customerEmail,
            customerPhone: customerPhone,
            amount: Math.round(grossRevenue),
            midtransOrderId: `scalev_${orderId}`,
            accessToken,
            status: "paid",
          });

          let trialGranted = false;
          if (customerEmail) {
            try {
              const buyer = await storage.getUserByEmail(customerEmail);
              if (buyer) {
                const now = new Date();
                const endDate = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
                await storage.createSubscription({
                  userId: buyer.id,
                  plan: "free_trial",
                  status: "active",
                  amount: 0,
                  currency: "IDR",
                  chatbotLimit: 1,
                  mayarOrderId: `scalev_ebook_${orderId}`,
                  startDate: now.toISOString(),
                  endDate: endDate.toISOString(),
                } as any);
                trialGranted = true;
                console.log(`[Scalev] Ebook trial 7 hari diaktifkan untuk ${customerEmail} (user ${buyer.id})`);
              } else {
                console.log(`[Scalev] Ebook: belum ada akun untuk ${customerEmail}, trial menunggu registrasi manual.`);
              }
            } catch (trialErr: any) {
              console.error(`[Scalev] Gagal aktivasi trial ebook untuk ${customerEmail}:`, trialErr?.message);
            }
          }

          if (customerEmail) {
            const { sendEbookFulfillmentEmail } = await import("./lib/email");
            const downloadUrl = `${baseUrl}/ebooks/trilogi-buku-1-dialog.pdf`;
            sendEbookFulfillmentEmail({
              to: customerEmail,
              customerName,
              downloadUrl,
              bonuses: [
                "Ebook Buku I — DIALOG (PDF, 160+ halaman) — sudah bisa didownload",
                "Prompt Khusus Buku I — menyusul via email terpisah",
                "Modul pendamping Buku I — menyusul via email terpisah",
                "Video pembelajaran NotebookLM — menyusul via email terpisah",
                "Trial 7 Hari coba merakit chatbot AI pertamamu",
              ],
              trialGranted,
            }).catch((emailErr: any) => console.error(`[Scalev] Gagal kirim email ebook ke ${customerEmail}:`, emailErr?.message));
          }
          console.log(`[Scalev] Ebook Buku I — DIALOG order diproses untuk ${customerEmail}`);
        }
      } else {
        // No mapping found — create a generic store order as placeholder (productId=0)
        await storage.createStoreOrder({
          productId: 0,
          customerName: customerName || "Customer",
          customerEmail: customerEmail,
          customerPhone: customerPhone,
          amount: Math.round(grossRevenue),
          midtransOrderId: `scalev_${orderId}`,
          accessToken,
          status: "paid_no_mapping",
        });
        console.log(`[Scalev] No mapping found for products: ${productNames.join(", ")}. Order recorded as paid_no_mapping.`);
      }

      res.status(200).json({ received: true });
    } catch (err: any) {
      console.error("[Scalev Webhook] Error:", err?.message);
      // Always return 200 to Scalev to prevent retries for our processing errors
      res.status(200).json({ received: true, error: err?.message });
    }
  });

  // ── Mayar Webhook ────────────────────────────────────────────────────────────
  app.post("/api/webhooks/mayar", async (req: any, res: any) => {
    try {
      const rawBody: string = typeof req.body === "string" ? req.body : JSON.stringify(req.body);
      const payload = typeof req.body === "string" ? JSON.parse(req.body) : req.body;
      console.log("[Mayar Webhook]", JSON.stringify(payload).slice(0, 500));

      // Verify signature if MAYAR_WEBHOOK_SECRET is set
      const webhookSecret = process.env.MAYAR_WEBHOOK_SECRET;
      if (webhookSecret) {
        const signature = req.headers["x-mayar-signature"] as string || "";
        const valid = await verifyMayarSignature(rawBody, signature, webhookSecret);
        if (!valid) {
          console.warn("[Mayar Webhook] Invalid signature — rejected");
          return res.status(401).json({ error: "Invalid signature" });
        }
      }

      const parsed = parseWebhookPayload(payload);
      const { event, id: transactionId, status, customerEmail, customerName, customerPhone, description, amount } = parsed;

      // Only process confirmed payments
      const isPaid = status === "paid" || status === "completed" || event === "payment.paid" || event === "invoice.paid";
      if (!isPaid) {
        console.log(`[Mayar Webhook] Skipping event=${event} status=${status}`);
        return res.status(200).json({ received: true, skipped: true });
      }

      if (!customerEmail) {
        console.warn("[Mayar Webhook] No customer email in payload");
        return res.status(200).json({ received: true, error: "no_email" });
      }

      const genUUID = () => Math.random().toString(36).slice(2) + Date.now().toString(36);
      const subEnd = new Date(); subEnd.setDate(subEnd.getDate() + 30);

      // --- Case 1: Chatbot product payment (description contains CHATBOT_AKSES-{agentId}) ---
      const chatbotAgentId = parseChatbotAgentId(description || "");
      if (chatbotAgentId) {
        const accessToken = genUUID();
        await storage.createClientSubscription({
          agentId: String(chatbotAgentId),
          customerName: customerName || "Customer",
          customerEmail,
          customerPhone: customerPhone || "",
          plan: "mayar",
          status: "active",
          amount: Math.round(amount),
          accessToken,
          startDate: new Date(),
          endDate: subEnd,
        } as any);
        console.log(`[Mayar Webhook] Chatbot #${chatbotAgentId} access created for ${customerEmail}`);
        return res.status(200).json({ received: true, type: "chatbot", agentId: chatbotAgentId });
      }

      // --- Case 2: Gustafta platform subscription (matched by mayarOrderId = transactionId) ---
      if (transactionId) {
        const sub = await storage.getSubscriptionByMayarOrderId(transactionId);
        if (sub && sub.status === "pending") {
          const { PLAN_CONFIGS } = await import("@shared/feature-plans");
          const planDuration = (PLAN_CONFIGS as any)[sub.plan]?.durationDays ?? subscriptionPlans[sub.plan as SubscriptionPlanKey]?.duration ?? 30;
          const now = new Date();
          const endDate = new Date(now.getTime() + planDuration * 24 * 60 * 60 * 1000);
          await (storage as any).updateSubscription?.(sub.id, {
            status: "active",
            startDate: now,
            endDate,
            amount: Math.round(amount) || sub.amount,
          });
          console.log(`[Mayar Webhook] Platform sub #${sub.id} activated for ${customerEmail} (plan: ${sub.plan})`);
          return res.status(200).json({ received: true, type: "platform_subscription", subscriptionId: sub.id });
        }
      }

      console.log(`[Mayar Webhook] No matching record for transactionId=${transactionId} email=${customerEmail}`);
      res.status(200).json({ received: true, type: "unmatched" });
    } catch (err: any) {
      console.error("[Mayar Webhook] Error:", err?.message);
      res.status(200).json({ received: true, error: err?.message });
    }
  });

  // ── Brevo Email Delivery Webhook ─────────────────────────────────────────────
  // Register this URL in Brevo Dashboard → Transactional → Webhooks:
  //   URL: https://<your-domain>/api/webhooks/brevo
  //   Events: delivered, soft_bounce, hard_bounce, spam, invalid_email, deferred
  //
  // In-memory bounce tracker (resets on server restart — for alerting purposes only).
  // For persistent storage, promote this to a DB table.
  const _brevoStats = { delivered: 0, bounced: 0, spam: 0, lastAlertAt: 0 };
  const BREVO_BOUNCE_ALERT_THRESHOLD = 0.2; // alert if >20% bounce rate over a window
  const BREVO_BOUNCE_ALERT_WINDOW = 60 * 60 * 1000; // 1-hour cooldown between alerts

  function _checkBrevoAlerts() {
    const total = _brevoStats.delivered + _brevoStats.bounced + _brevoStats.spam;
    if (total < 10) return; // need at least 10 events before alerting
    const bounceRate = (_brevoStats.bounced + _brevoStats.spam) / total;
    const now = Date.now();
    if (bounceRate > BREVO_BOUNCE_ALERT_THRESHOLD && (now - _brevoStats.lastAlertAt) > BREVO_BOUNCE_ALERT_WINDOW) {
      _brevoStats.lastAlertAt = now;
      console.error(
        `[Brevo ALERT] High bounce/spam rate detected: ${Math.round(bounceRate * 100)}% ` +
        `(bounced=${_brevoStats.bounced}, spam=${_brevoStats.spam}, delivered=${_brevoStats.delivered}). ` +
        `Check Brevo dashboard and verify sender domain/reputation.`
      );
    }
  }

  app.post("/api/webhooks/brevo", async (req: any, res: any) => {
    try {
      // Optional authenticity check via a shared secret set in Brevo dashboard
      // (Brevo → Transactional → Webhooks → "Secret" field).
      // Set BREVO_WEBHOOK_SECRET env var to enable; leave unset to skip.
      const webhookSecret = process.env.BREVO_WEBHOOK_SECRET;
      if (webhookSecret) {
        const incoming = req.headers["x-brevo-webhook-secret"] || req.headers["x-webhook-secret"] || "";
        if (incoming !== webhookSecret) {
          console.warn("[Brevo Webhook] Rejected — invalid or missing webhook secret");
          return res.status(401).json({ error: "Unauthorized" });
        }
      }

      // Brevo sends an array of events or a single event object
      const rawEvents = Array.isArray(req.body) ? req.body : [req.body];
      let processed = 0;
      let failed = 0;

      for (const evt of rawEvents) {
        try {
          const event: string = evt.event || evt.type || "unknown";
          const email: string = evt.email || evt.to || "";
          const messageId: string = evt.messageId || evt["message-id"] || "";
          const subject: string = evt.subject || "";
          const reason: string = evt.reason || evt.error || "";
          const ts: number = evt.ts || evt.timestamp || Math.floor(Date.now() / 1000);

          // Safe tag normalization: Brevo can send `tag` as a plain string ("otp"),
          // a JSON-encoded string ("[\"otp\"]"), or `tags` as a proper array.
          // Never JSON.parse an arbitrary string — treat it as a plain tag instead.
          let tags: string[] = [];
          if (Array.isArray(evt.tags)) {
            tags = evt.tags.map(String);
          } else if (Array.isArray(evt.tag)) {
            tags = evt.tag.map(String);
          } else if (typeof evt.tag === "string" && evt.tag.length > 0) {
            // Attempt JSON parse only when the string looks like a JSON array
            if (evt.tag.trim().startsWith("[")) {
              try { tags = JSON.parse(evt.tag); } catch { tags = [evt.tag]; }
            } else {
              tags = [evt.tag];
            }
          }

          const isOtpEmail = tags.includes("otp") ||
            subject.toLowerCase().includes("verifikasi") ||
            subject.toLowerCase().includes("otp");

          switch (event) {
            case "delivered":
              _brevoStats.delivered++;
              console.log(`[Brevo] ✓ DELIVERED — to=${email} messageId=${messageId} tags=[${tags}] ts=${ts}`);
              break;

            case "hard_bounce":
              _brevoStats.bounced++;
              console.error(
                `[Brevo] ✗ HARD BOUNCE${isOtpEmail ? " [OTP EMAIL]" : ""} — ` +
                `to=${email} reason="${reason}" messageId=${messageId} ts=${ts}`
              );
              if (isOtpEmail) {
                console.warn(`[Brevo] OTP hard bounce for ${email} — user will not receive verification code. Reason: ${reason || "unknown"}`);
              }
              break;

            case "soft_bounce":
              _brevoStats.bounced++;
              console.warn(
                `[Brevo] ~ SOFT BOUNCE${isOtpEmail ? " [OTP EMAIL]" : ""} — ` +
                `to=${email} reason="${reason}" messageId=${messageId} ts=${ts}`
              );
              break;

            case "spam":
              _brevoStats.spam++;
              console.error(
                `[Brevo] ⚠ SPAM REPORT${isOtpEmail ? " [OTP EMAIL]" : ""} — ` +
                `to=${email} messageId=${messageId} ts=${ts}`
              );
              break;

            case "invalid_email":
              _brevoStats.bounced++;
              console.error(
                `[Brevo] ✗ INVALID EMAIL${isOtpEmail ? " [OTP EMAIL]" : ""} — ` +
                `to=${email} messageId=${messageId} ts=${ts}`
              );
              break;

            case "deferred":
              console.warn(
                `[Brevo] ~ DEFERRED — to=${email} reason="${reason}" messageId=${messageId} ts=${ts}`
              );
              break;

            case "open":
            case "click":
            case "unsubscribed":
              console.log(`[Brevo] ${event} — to=${email} ts=${ts}`);
              break;

            default:
              console.log(`[Brevo] Event "${event}" — to=${email} ts=${ts} body=${JSON.stringify(evt).slice(0, 200)}`);
          }

          _checkBrevoAlerts();
          processed++;
        } catch (evtErr: any) {
          // Isolate per-event failures so one bad payload doesn't drop the rest
          failed++;
          console.error(`[Brevo Webhook] Failed to process event: ${evtErr?.message} — payload=${JSON.stringify(evt).slice(0, 200)}`);
        }
      }

      res.status(200).json({ received: true, events: rawEvents.length, processed, failed });
    } catch (err: any) {
      console.error("[Brevo Webhook] Error processing payload:", err?.message);
      // Always return 200 to Brevo so it doesn't retry indefinitely
      res.status(200).json({ received: true, error: err?.message });
    }
  });

